import React, { createContext, useState, useContext } from 'react';

const DataContext = createContext(null);

export const DataProvider = ({ children }) => {
  // 1. Dữ liệu mẫu Staff (Thêm trường status và role chi tiết)
  // Role: 'chief_admin', 'reg_admin', 'op_admin', 'staff'
  // Status: 'active', 'suspended'
  const [staffList, setStaffList] = useState([
    { id: 1, username: 'chief', password: '123', name: 'Sếp Tổng (Chief)', role: 'chief_admin', status: 'active' },
    { id: 2, username: 'reg', password: '123', name: 'Quản lý Quy chế (Reg)', role: 'reg_admin', status: 'active' },
    { id: 3, username: 'op', password: '123', name: 'Quản lý Vận hành (Op)', role: 'op_admin', status: 'active' },
    { id: 4, username: 'nv1', password: '123', name: 'Nguyễn Văn A', role: 'staff', status: 'active' },
  ]);

  // 2. Danh sách hình thức kỷ luật (Do Regulatory ban hành)
  const [disciplineTypes, setDisciplineTypes] = useState([
    { id: 1, name: 'Nhắc nhở miệng', level: 'Nhẹ' },
    { id: 2, name: 'Trừ 10% KPI tháng', level: 'Trung bình' },
    { id: 3, name: 'Cảnh cáo toàn công ty', level: 'Nặng' }
  ]);

  // 3. Dữ liệu Tasks (Thêm field: recurrence, isRecurring)
  const [tasks, setTasks] = useState([
    { 
      id: 1715000000000, 
      title: 'Thiết kế Logo mới', 
      assigneeId: 4, 
      progress: 50, 
      startDate: '2023-10-20',
      deadline: '2023-10-25', 
      discipline: 'Trừ 10% KPI tháng', 
      recurrence: 'none', // none, daily, weekly, monthly
      completedDate: null,
      reason: '' 
    }
  ]);

  const [attendanceLogs, setAttendanceLogs] = useState([]);
  const [facilityLogs, setFacilityLogs] = useState([]);

  // --- CÁC HÀM XỬ LÝ NHÂN SỰ (CHIEF ADMIN) ---

  const addStaff = (s) => setStaffList([...staffList, { ...s, id: Date.now(), role: 'staff', status: 'active' }]);
  
  const deleteStaff = (id) => {
    setStaffList(staffList.filter(staff => staff.id !== id));
  };

  const updatePassword = (id, newPass) => {
    setStaffList(staffList.map(s => s.id === id ? { ...s, password: newPass } : s));
  };

  // [MỚI] Hàm Bổ nhiệm nhân sự (Change Role)
  const promoteStaff = (id, newRole) => {
    setStaffList(staffList.map(s => s.id === id ? { ...s, role: newRole } : s));
  };

  // [MỚI] Hàm Đình chỉ / Kích hoạt lại (Toggle Status)
  const toggleStaffStatus = (id) => {
    setStaffList(staffList.map(s => {
      if (s.id === id) {
        return { ...s, status: s.status === 'active' ? 'suspended' : 'active' };
      }
      return s;
    }));
  };

  // --- CÁC HÀM XỬ LÝ QUY ĐỊNH (REGULATORY ADMIN) ---
  
  // [MỚI] Thêm loại hình kỷ luật
  const addDisciplineType = (name, level) => {
    setDisciplineTypes([...disciplineTypes, { id: Date.now(), name, level }]);
  };

  // [MỚI] Xóa loại hình kỷ luật
  const removeDisciplineType = (id) => {
    setDisciplineTypes(disciplineTypes.filter(d => d.id !== id));
  };

  // --- CÁC HÀM XỬ LÝ CÔNG VIỆC (OPERATIONAL ADMIN) ---

  const addTask = (t) => setTasks([...tasks, { 
    ...t, 
    id: Date.now(), 
    progress: 0, 
    reason: '',
    completedDate: null 
  }]);

  // [MỚI] Chuyển việc cho người khác (Cover urgent)
  const reassignTask = (taskId, newAssigneeId) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, assigneeId: parseInt(newAssigneeId) } : t));
  };

  const updateTaskProgress = (id, p, reason = '') => {
    const now = new Date().toISOString().split('T')[0];
    setTasks(tasks.map(t => 
      t.id === id ? { 
        ...t, 
        progress: p, 
        reason: reason,
        completedDate: p === 100 ? now : null 
      } : t
    ));
  };

  const addAttendance = (log) => setAttendanceLogs([...attendanceLogs, log]);
  const addFacilityLog = (log) => setFacilityLogs([...facilityLogs, log]);

  return (
    <DataContext.Provider value={{ 
      staffList, addStaff, deleteStaff, updatePassword, promoteStaff, toggleStaffStatus,
      disciplineTypes, addDisciplineType, removeDisciplineType,
      tasks, addTask, updateTaskProgress, reassignTask,
      attendanceLogs, addAttendance, 
      facilityLogs, addFacilityLog 
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => useContext(DataContext);
